@@ -1266,7 +1266,52 @@ Value *InstCombinerImpl::foldEqOfParts(Value *Cmp0, Value *Cmp1, bool IsAnd) {
   return Builder.CreateICmp(Pred, LValue, RValue);
 }

-/// Reduce logic-of-compares with equality to a constant by substituting a
+/// Fold (icmp ult X, C) & (icmp eq (X & Mask), V) -> (icmp eq (X & Mask), V)
+/// when Mask is a negated power of 2, V is aligned to the mask, and
+/// all values that satisfy (X & Mask) == V are less than C.
+/// For example: (X < 5) & ((X & -2) == 2) -> ((X & -2) == 2)
+/// Because when (X & -2) == 2, X must be 2 or 3, both of which are < 5.
+static Value *foldAndOfRangeCheckAndMaskedEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
+                                             InstCombiner::BuilderTy &Builder) {
+  // Match: (icmp ult X, C) & (icmp eq (X & Mask), V)
+  Value *X0, *X1;
+  const APInt *C0, *V, *Mask;
+  
+  // Cmp0 should be: icmp ult X, C
+  if (!match(Cmp0, m_SpecificICmp(ICmpInst::ICMP_ULT, m_Value(X0), m_APInt(C0))))
+    return nullptr;
+  
+  // Cmp1 should be: icmp eq (X & Mask), V where Mask is a negated power of 2
+  if (!match(Cmp1, m_SpecificICmp(ICmpInst::ICMP_EQ,
+                                  m_OneUse(m_And(m_Value(X1), m_NegatedPower2(Mask))),
+                                  m_APInt(V))))
+    return nullptr;
+  
+  // X0 and X1 must be the same value
+  if (X0 != X1)
+    return nullptr;
+  
+  // M = -Mask (the power of 2 that Mask clears)
+  // For Mask = -2 (0xFE), M = 2
+  // For Mask = -4 (0xFC), M = 4
+  APInt M = -(*Mask);
+  
+  // V must be aligned to the mask: V & ~Mask == 0
+  // ~Mask = M - 1, so V & (M - 1) == 0
+  if ((*V & (M - 1)) != 0)
+    return nullptr;
+  
+  // All possible values of X are V, V+1, ..., V+M-1
+  // The maximum is V + M - 1
+  // For the range check to be redundant: V + M - 1 < C, i.e., V + M <= C
+  if ((*V + M).ugt(*C0))
+    return nullptr;
+  
+  // The range check is always true when the masked check is true,
+  // so we can just return the masked check.
+  return Cmp1;
+}
+
 /// common operand with the constant. Callers are expected to call this with
 /// Cmp0/Cmp1 switched to handle logic op commutativity.
 static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
@@ -3428,6 +3473,15 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldIsPowerOf2OrZero(RHS, LHS, IsAnd, Builder, *this))
     return V;

+  // Fold (icmp ult X, C) & (icmp eq (X & Mask), V) -> (icmp eq (X & Mask), V)
+  // when the masked check implies the range check.
+  if (IsAnd) {
+    if (Value *V = foldAndOfRangeCheckAndMaskedEq(LHS, RHS, Builder))
+      return V;
+    if (Value *V = foldAndOfRangeCheckAndMaskedEq(RHS, LHS, Builder))
+      return V;
+  }
